-- ============================================================
-- DELETE ALL SEED/DUMMY DATA
-- Run this in the Supabase SQL Editor (one-time operation)
-- ============================================================

-- Delete in order: children first, then parents (respects foreign keys)

-- 1. Messages in conversations involving seed users
DELETE FROM messages WHERE conversation_id IN (
  SELECT id FROM conversations WHERE participants && ARRAY[
    'a0000000-0000-0000-0000-000000000001'::uuid,
    'a0000000-0000-0000-0000-000000000002'::uuid,
    'a0000000-0000-0000-0000-000000000003'::uuid,
    'a0000000-0000-0000-0000-000000000004'::uuid,
    'a0000000-0000-0000-0000-000000000005'::uuid,
    'a0000000-0000-0000-0000-000000000006'::uuid,
    'a0000000-0000-0000-0000-000000000007'::uuid,
    'a0000000-0000-0000-0000-000000000008'::uuid
  ]
);

-- 2. Conversations involving seed users
DELETE FROM conversations WHERE participants && ARRAY[
  'a0000000-0000-0000-0000-000000000001'::uuid,
  'a0000000-0000-0000-0000-000000000002'::uuid,
  'a0000000-0000-0000-0000-000000000003'::uuid,
  'a0000000-0000-0000-0000-000000000004'::uuid,
  'a0000000-0000-0000-0000-000000000005'::uuid,
  'a0000000-0000-0000-0000-000000000006'::uuid,
  'a0000000-0000-0000-0000-000000000007'::uuid,
  'a0000000-0000-0000-0000-000000000008'::uuid
];

